DeploymentType.DetectionMethod:
$InstalledItem = (Get-ChildItem -Path "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall" -ErrorAction SilentlyContinue | where-object {$_.GetValue("DisplayName") -eq "Microsoft Power BI Desktop for Report Server (x64)"})
if (-not ([System.String]::IsNullorEmpty($InstalledItem))){
    if ([Version]$($InstalledItem.GetValue("DisplayVersion")) -ge [Version]"$Version"){
        write-Output "Installed"
    }
}
